import UIKit
import Alamofire

class StockViewController: UIViewController {
    @IBOutlet weak var stockPriceLabel: UILabel!
    @IBOutlet weak var quantityTextField: UITextField!
    @IBOutlet weak var executeButton: UIButton!

    let apiKey = "YOUR_API_KEY"

    override func viewDidLoad() {
        super.viewDidLoad()
        fetchStockPrice()
    }

    func fetchStockPrice() {
        guard let symbol = "AAPL" else { return }
        let url = "https://api.example.com/stock/\(symbol)/price?key=\(apiKey)"
        
        Alamofire.request(url, method: .get).responseJSON { response in
            switch response.result {
            case .success(let value):
                if let price = (value as? [String: Any])?["price"] as? Double {
                    DispatchQueue.main.async {
                        self.stockPriceLabel.text = "$\(price)"
                    }
                }
            case .failure(let error):
                print("Error fetching stock price: \(error)")
            }
        }
    }

    @IBAction func executeTrade(_ sender: UIButton) {
        guard let symbol = "AAPL", let quantityString = quantityTextField.text, let quantity = Int(quantityString) else { return }
        
        let url = "https://api.example.com/stock/\(symbol)/buy?key=\(apiKey)"
        let parameters: [String: Any] = ["quantity": quantity]
        
        Alamofire.request(url, method: .post, parameters: parameters, encoding: JSONEncoding.default).responseJSON { response in
            switch response.result {
            case .success(let value):
                if let message = (value as? [String: Any])?["message"] as? String {
                    DispatchQueue.main.async {
                        self.showAlert(message)
                    }
                }
            case .failure(let error):
                print("Error executing trade: \(error)")
            }
        }
    }

    func showAlert(_ message: String) {
        let alert = UIAlertController(title: "Trade Executed", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true, completion: nil)
    }
}